def check_occurences(tuples):
    # Kwanza, tunapata idadi ya kila tuple
    tuple_counts = {}
    for tup in tuples:
        count = len(tup)
        if count in tuple_counts:
            tuple_counts[count].append(tup)
        else:
            tuple_counts[count] = [tup]

    # Kisha, tunapata idadi ya kila tuple
    max_count = max(tuple_counts.keys())

    # Sasa, tunapata idadi ya kila tuple
    tuple_occurences = {}
    for tup in tuples:
        count = len(tup)
        if count in tuple_occurences:
            tuple_occurences[count].append(tup)
        else:
            tuple_occurences[count] = [tup]

    # Hatimaye, tunapata idadi ya kila tuple ambayo ina maingizo sawa
    similar_tuples = {}
    for count in tuple_occurences:
        if count == max_count:
            similar_tuples[count] = tuple_occurences[count]

    return similar_tuples

# Kwa mfano, ikiwa tunataka kujua ni ipi kati ya tuples zifuatazo ambazo zina maingizo sawa
tuples = [(1, 2, 3), (4, 5, 6), (1, 2, 3), (7, 8, 9), (1, 2, 3)]
print(check_occurences(tuples))
```

