def Check_Solution(a, b, c):
    # Kwanza, tunahitaji kupata mizizi ya equation ya quadratic
    # Mizizi inatolewa na fomula ya quadratic: x = (-b ± √(b^2 - 4ac)) / 2a
    discriminant = b**2 - 4*a*c

    # Ikiwa discriminant ni hasi, equation haizidi mizizi halisi
    if discriminant < 0:
        return "Equation haizidi mizizi halisi"

    # Ikiwa discriminant ni sawa na 0, mizizi ni sawa
    elif discriminant == 0:
        root = -b / (2*a)
        return "Mizizi ni sawa: " + str(root) + " = " + str(root) + "^2"

    # Ikiwa discriminant ni chanya, mizizi ni tofauti
    else:
        root1 = (-b + discriminant**0.5) / (2*a)
        root2 = (-b - discriminant**0.5) / (2*a)

        # Kisha, tunahitaji kubainisha ikiwa mizizi ni sawa au siyo
        # Ikiwa mizizi ni sawa, lazima ziwe sawa na kinyume chake
        if root1 == root2:
            return "Mizizi ni sawa: " + str(root1) + " = " + str(root2) + " = " + str(root1) + "^2"
        else:
            # Ikiwa mizizi ni tofauti, lazima ziwe kinyume chake
            if root1 * root2 == 1:
                return "Mizizi ni kinyume chake: " + str(root1) + " na " + str(root2)
            else:
                return "Mizizi si kinyume chake"
```

