def tuple_to_dict(tup):
    # Kwanza, tunahitaji kuhakikisha kwamba orodha iliyotolewa ina idadi isiyo ya kawaida ya vipengele.
    if len(tup) % 2 != 0:
        raise ValueError("Orodha lazima iwe na idadi isiyo ya kawaida ya vipengele")

    # Kisha, tunatengeneza orodha mpya ambapo kila elementi ya 0 inaonyeshwa kama key na elementi ya 1 inaonyeshwa kama value.
    # Tunatumia kikokotoo ya dictionary comprehension kufanya hivyo.
    return {tup[i]: tup[i+1] for i in range(0, len(tup), 2)}

# Kwa mfano, ikiwa orodha iliyotolewa ni (1, 2, 3, 4, 5, 6), orodha mpya itakuwa {1: 2, 3: 4, 5: 6}.
print(tuple_to_dict((1, 2, 3, 4, 5, 6)))  # {1: 2, 3: 4, 5: 6}
```

