```python
def rearange_string(s):
    # Hesabu idadi ya vikwazo vya kipekee katika mstari wa kukokotoa
    char_count = {}
    for char in s:
        if char in char_count:
            char_count[char] += 1
        else:
            char_count[char] = 1

    # Hesabu idadi ya vikwazo vya kipekee
    odd_count = 0
    for count in char_count.values():
        if count % 2 != 0:
            odd_count += 1

    # Ikiwa idadi ya vikwazo ni 1, basi tunaweza kubadilisha neno kwa mpangilio ambapo vikwazo vyote ni tofauti
    if odd_count > 1:
        return False

    # Kwa kuwa tunaweza kubadilisha neno kwa mpangilio ambapo vikwazo vyote ni tofauti, tunaweza kubadilisha neno kwa mpangilio wowote
    return True
```

