```python
def get_odd_occurence(arr):
    # Kwanza, tunapata nambari ambayo inaonekana mara nyingi zaidi katika orodha
    majority_element = None
    count = 0
    for num in arr:
        if count == 0:
            majority_element = num
            count = 1
        elif majority_element == num:
            count += 1
        else:
            count -= 1

    # Kisha, tunapata idadi ya mara ambayo nambari hii inaonekana katika orodha
    majority_count = arr.count(majority_element)

    # Ikiwa nambari hii inaonekana mara mbili tu katika orodha, basi tunapata nambari ambayo inaonekana mara isiyo ya kawaida
    if majority_count == len(arr):
        return None  # Nambari hii inaonekana mara nyingi zaidi, kwa hivyo haiwezi kuwa nambari ambayo inaonekana mara isiyo ya kawaida

    # Kisha, tunapata nambari ambayo inaonekana mara mbili tu katika orodha
    odd_count_dict = {}
    for num in arr:
        if num in odd_count_dict:
            odd_count_dict[num] += 1
        else:
            odd_count_dict[num] = 1

    # Hatimaye, tunapata nambari ambayo inaonekana mara isiyo ya kawaida
    for num, count in odd_count_dict.items():
        if count % 2 != 0:
            return num

