def find_Extra(arr1, arr2):
    # Kwanza, tunahitaji kuamua idadi ya elements katika kila array
    len1 = len(arr1)
    len2 = len(arr2)

    # Kisha, tunahitaji kuamua idadi ya elements katika array ya pili ambayo ni sawa na idadi ya elements katika array ya kwanza
    diff = abs(len1 - len2)

    # Ikiwa array ya kwanza ni kubwa kuliko array ya pili, tunahitaji kuchunguza elements katika array ya kwanza
    if len1 > len2:
        for i in range(len1):
            # Ikiwa element hii ni sawa na element katika array ya pili, tunahitaji kuendelea kuchunguza elements zingine
            if i + diff in range(len2) and arr1[i] == arr2[i + diff]:
                continue
            # Ikiwa element hii si sawa na element katika array ya pili, tunahitaji kubainisha kuwa ni element ya ziada
            else:
                return i
    # Ikiwa array ya pili ni kubwa kuliko array ya kwanza, tunahitaji kuchunguza elements katika array ya pili
    else:
        for i in range(len2):
            # Ikiwa element hii ni sawa na element katika array ya kwanza, tunahitaji kuendelea kuchunguza elements zingine
            if i - diff in range(len1) and arr2[i] == arr1[i - diff]:
                continue
            # Ikiwa element hii si sawa na element katika array ya kwanza, tunahitaji kubainisha kuwa ni element ya ziada
            else:
                return i

