```python
def equilibrium_index(arr):
    # Kuanza kwa kuondoa maadili yaliyopunguzwa kwa kila index
    reduced_arr = [0] * len(arr)
    for i in range(1, len(arr)):
        reduced_arr[i] = reduced_arr[i-1] + arr[i-1]

    # Kisha, kwa kila index, kuhesabu jumla ya maadili yaliyopunguzwa kabla na baada ya index hiyo
    for i in range(len(arr)):
        if i > 0:
            reduced_before = reduced_arr[i-1]
        else:
            reduced_before = 0

        if i < len(arr) - 1:
            reduced_after = reduced_arr[-1] - reduced_arr[i]
        else:
            reduced_after = 0

        # Ikiwa jumla ya maadili yaliyopunguzwa kabla na baada ya index hiyo ni sawa, basi index hiyo ni index ya usawa
        if reduced_before == reduced_after:
            return i

    # Ikiwa hakuna index ya usawa, kisha index ya usawa ni -1
    return -1
```

