```python
def find_Nth_Digit(num1, num2, n):
    # Kwanza, tunahitaji kubainisha sehemu ya sahihi ya nambari mbili
    def gcd(a, b):
        while b != 0:
            a, b = b, a % b
        return a

    # Kisha, tunahitaji kubainisha kizidishio cha kawaida cha nambari mbili
    def lcm(a, b):
        return a * b // gcd(a, b)

    # Sasa, tunaweza kubainisha sehemu ya sahihi ya nambari mbili
    def simplify_fraction(numerator, denominator):
        common_divisor = gcd(numerator, denominator)
        return numerator // common_divisor, denominator // common_divisor

    # Kisha, tunahitaji kubainisha nambari ya nth katika sehemu ya sahihi ya nambari mbili
    def find_nth_digit(numerator, denominator, n):
        # Kwanza, tunahitaji kubainisha idadi ya tarakimu katika sehemu ya sahihi ya nambari mbili
        decimal_places = 0
        while numerator != 0:
            numerator *= 10
            decimal_places += 1
            if decimal_places >= n:
                break

        # Kisha, tunaweza kubainisha nambari ya nth katika sehemu ya sahihi ya nambari mbili
        if decimal_places < n:
            return -1  # Ikiwa nambari ya nth haijafikiwa, tunarejesha -1
        else:
            return numerator // (10 ** (decimal_places - n))

    # Sasa, tunaweza kubainisha nambari ya nth katika sehemu ya sahihi ya nambari mbili
    numerator, denominator = simplify_fraction(num1, num2)
    return find_nth_digit(numerator, denominator, n)
```

