```python
import math

def binomial_Coeff(n, k):
    # Hesabu viambajengo vya binomial kwa kutumia fomula ya Pascal
    return math.comb(n, k)

def jumla_ya_bidhaa(n, k):
    # Hesabu jumla ya bidhaa za viambajengo vya binomial
    jumla = 0
    for i in range(k + 1):
        jumla += binomial_Coeff(n, i) * binomial_Coeff(n, k - i)
    return jumla

