def solution(a, b, n):
    # Kwanza, tunahitaji kuangalia ikiwa kigezo kimoja ni sawa na 0
    if a == 0:
        # Ikiwa a ni sawa na 0, basi tunahitaji kuangalia ikiwa b ni sawa na 0
        if b == 0:
            # Ikiwa b pia ni sawa na 0, basi hatuwezi kupata suluhisho la x na y
            if n == 0:
                return "Suluhisho zote"
            else:
                return "Suluhisho halipo"
        else:
            # Ikiwa b si sawa na 0, basi tunaweza kupata x na y
            x = n // b
            y = n % b
            return f"x = {x}, y = {y}"
    elif b == 0:
        # Ikiwa b ni sawa na 0, basi tunaweza kupata x na y
        x = n // a
        y = n % a
        return f"x = {x}, y = {y}"
    else:
        # Ikiwa b si sawa na 0, basi tunaweza kupata x na y kwa kutumia fomula ya Euclidean
        def extended_gcd(a, b):
            if a == 0:
                return b, 0, 1
            else:
                gcd, x, y = extended_gcd(b % a, a)
                return gcd, y - (b // a) * x, x

        gcd, x, y = extended_gcd(a, b)
        if n % gcd != 0:
            return "Suluhisho halipo"
        else:
            x *= n // gcd
            y *= n // gcd
            return f"x = {x}, y = {y}"

# Kwa mfano, ikiwa a = 2, b = 3, na n = 7, basi tunaweza kusema:
print(solution(2, 3, 7))
