```python
def lcs_of_three(s1, s2, s3):
    # Kwanza, tutapata mfuatano mrefu zaidi wa kawaida kati ya s1 na s2
    lcs_1_2 = [[0] * (len(s2) + 1) for _ in range(len(s1) + 1)]
    for i in range(1, len(s1) + 1):
        for j in range(1, len(s2) + 1):
            if s1[i - 1] == s2[j - 1]:
                lcs_1_2[i][j] = lcs_1_2[i - 1][j - 1] + 1
            else:
                lcs_1_2[i][j] = max(lcs_1_2[i - 1][j], lcs_1_2[i][j - 1])

    # Kisha, tutapata mfuatano mrefu zaidi wa kawaida kati ya s2 na s3
    lcs_2_3 = [[0] * (len(s3) + 1) for _ in range(len(s2) + 1)]
    for i in range(1, len(s2) + 1):
        for j in range(1, len(s3) + 1):
            if s2[i - 1] == s3[j - 1]:
                lcs_2_3[i][j] = lcs_2_3[i - 1][j - 1] + 1
            else:
                lcs_2_3[i][j] = max(lcs_2_3[i - 1][j], lcs_2_3[i][j - 1])

    # Hatimaye, tutapata mfuatano mrefu zaidi wa kawaida kati ya s1 na s3 kwa kutumia mfuatano mrefu zaidi wa kawaida kati ya s1 na s2 na kati ya s2 na s3
    lcs_1_3 = [[0] * (len(s3) + 1) for _ in range(len(s1) + 1)]
    for i in range(1, len(s1) + 1):
        for j in range(1, len(s3) + 1):
            if s1[i - 1] == s3[j - 1]:
                lcs_1_3[i][j] = lcs_1_3[i - 1][j - 1] + 1
            else:
                lcs_1_3[i][j] = max(lcs_1_3[i - 1][j], lcs_1_3[i][j - 1])

    # Sasa, tutapata mfuatano mrefu zaidi wa kawaida kati ya s1 na s3
    lcs = []
    i, j = len(s1), len(s3)
    while i > 0 and j > 0:
        if s1[i - 1] == s3[j - 1]:
            lcs.append(s1[i - 1])
            i -= 1
            j -= 1
        elif lcs_1_2[i][j - 1] > lcs_1_2[i - 1][j]:
            j -= 1
        else:
            i -= 1

    # Kwa kuwa tulipata mfuatano mrefu zaidi wa kawaida kati ya s1 na s3, sasa tunahitaji kupata mfuatano mrefu zaidi wa kawaida kati ya s2 na mfuatano huu
    lcs_2 = []
    i, j = len(s2), len(lcs)
    while i > 0 and j > 0:
        if s2[i - 1] == lcs[j - 1]:
            lcs_2.append(s2[i - 1])
            i -= 1
            j -= 1
        elif lcs_2_3[i][j - 1] > lcs_2_3[i - 1][j]:
            j -= 1
        else:
            i -= 1

    # Hatimaye, tunabadilisha mfuatano mrefu zaidi wa kawaida kati ya s2 na mfuatano mrefu zaidi wa kawaida kati ya s1 na s3
    lcs = lcs_2[::-1] + lcs[::-1]

    return ''.join(lcs)

